/**
 * Wide-event request context for the Brain server.
 *
 * Implements the "wide event" pattern (https://loggingsucks.com):
 * Instead of scattering 20 log lines per request, accumulate all
 * context into a single mutable bag. At request completion, the
 * instrumentation layer flushes everything onto the OTel span —
 * one comprehensive event per request with all business context.
 *
 * Any code in the request path can call `getRequestContext().set()`
 * to enrich the event. No need to pass context objects through
 * every function signature — it rides OTel's AsyncLocalStorage.
 */

import { context, createContextKey } from "@opentelemetry/api";

const REQUEST_CONTEXT_KEY = createContextKey("brain.request-context");

export type RequestAttributes = Record<string, string | number | boolean | string[]>;

export interface RequestContext {
  /** Set one or more attributes on the wide event. */
  set(attrs: RequestAttributes): void;

  /** Set a single attribute. */
  setAttribute(key: string, value: string | number | boolean | string[]): void;

  /** Read all accumulated attributes. */
  getAttributes(): Readonly<RequestAttributes>;
}

class RequestContextImpl implements RequestContext {
  private readonly attrs: RequestAttributes = {};

  set(attrs: RequestAttributes): void {
    for (const [key, value] of Object.entries(attrs)) {
      this.attrs[key] = value;
    }
  }

  setAttribute(key: string, value: string | number | boolean | string[]): void {
    this.attrs[key] = value;
  }

  getAttributes(): Readonly<RequestAttributes> {
    return this.attrs;
  }
}

/**
 * Create a new RequestContext and return it along with an OTel context
 * that carries it. Used by the instrumentation layer at request start.
 */
export function createRequestContext(): { ctx: RequestContext; otelContext: ReturnType<typeof context.active> } {
  const ctx = new RequestContextImpl();
  const otelContext = context.active().setValue(REQUEST_CONTEXT_KEY, ctx);
  return { ctx, otelContext };
}

/**
 * Get the RequestContext for the current request.
 * Returns a no-op context if called outside a traced request
 * (e.g. during startup or in background jobs).
 */
export function getRequestContext(): RequestContext {
  const ctx = context.active().getValue(REQUEST_CONTEXT_KEY) as RequestContext | undefined;
  return ctx ?? NOOP_CONTEXT;
}

const NOOP_CONTEXT: RequestContext = {
  set() {},
  setAttribute() {},
  getAttributes() {
    return {};
  },
};

