  1→/**
  2→ * OpenTelemetry SDK bootstrap for the Brain server.
  3→ *
  4→ * Pure function that reads env and returns a TelemetryHandle with
  5→ * TracerProvider, MeterProvider, LoggerProvider, and a shutdown function.
  6→ *
  7→ * Exporter selection:
  8→ * - Console exporters when OTEL_EXPORTER_OTLP_ENDPOINT is unset (dev)
  9→ * - OTLP HTTP exporters when OTEL_EXPORTER_OTLP_ENDPOINT is set (prod)
 10→ *
 11→ * Graceful degradation: if initialization fails, returns a no-op handle
 12→ * so the server can still start.
 13→ */
 14→
 15→import { trace, metrics, context, type TracerProvider as ApiTracerProvider, type MeterProvider as ApiMeterProvider } from "@opentelemetry/api";
 16→import { logs, type LoggerProvider as ApiLoggerProvider } from "@opentelemetry/api-logs";
 17→import { resourceFromAttributes } from "@opentelemetry/resources";
 18→import type { Resource } from "@opentelemetry/resources";
 19→import { ATTR_SERVICE_NAME, ATTR_SERVICE_VERSION } from "@opentelemetry/semantic-conventions";
 20→import { BasicTracerProvider, BatchSpanProcessor, ConsoleSpanExporter, SimpleSpanProcessor } from "@opentelemetry/sdk-trace-base";
 21→import { MeterProvider, PeriodicExportingMetricReader, ConsoleMetricExporter } from "@opentelemetry/sdk-metrics";
 22→import { LoggerProvider, SimpleLogRecordProcessor, ConsoleLogRecordExporter } from "@opentelemetry/sdk-logs";
 23→import { AsyncLocalStorageContextManager } from "@opentelemetry/context-async-hooks";
 24→
 25→export type ExporterType = "console" | "otlp" | "noop";
 26→
 27→export interface TelemetryHandle {
 28→  readonly tracerProvider: ApiTracerProvider;
 29→  readonly meterProvider: ApiMeterProvider;
 30→  readonly loggerProvider: ApiLoggerProvider;
 31→  readonly exporterType: ExporterType;
 32→  readonly shutdown: () => Promise<void>;
 33→}
 34→
 35→function buildResource(): Resource {
 36→  const serviceVersion = process.env.SERVICE_VERSION ?? "unknown";
 37→  return resourceFromAttributes({
 38→    [ATTR_SERVICE_NAME]: "brain-server",
 39→    [ATTR_SERVICE_VERSION]: serviceVersion,
 40→  });
 41→}
 42→
 43→function createConsoleProviders(resource: Resource): {
 44→  tracerProvider: BasicTracerProvider;
 45→  meterProvider: MeterProvider;
 46→  loggerProvider: LoggerProvider;
 47→} {
 48→  const tracerProvider = new BasicTracerProvider({
 49→    resource,
 50→    spanProcessors: [new SimpleSpanProcessor(new ConsoleSpanExporter())],
 51→  });
 52→
 53→  const meterProvider = new MeterProvider({
 54→    resource,
 55→    readers: [new PeriodicExportingMetricReader({ exporter: new ConsoleMetricExporter() })],
 56→  });
 57→
 58→  const loggerProvider = new LoggerProvider({
 59→    resource,
 60→    processors: [new SimpleLogRecordProcessor(new ConsoleLogRecordExporter())],
 61→  });
 62→
 63→  return { tracerProvider, meterProvider, loggerProvider };
 64→}
 65→
 66→function createOtlpProviders(resource: Resource, endpoint: string): {
 67→  tracerProvider: BasicTracerProvider;
 68→  meterProvider: MeterProvider;
 69→  loggerProvider: LoggerProvider;
 70→} {
 71→  // Bun supports synchronous require() for these packages
 72→  const { OTLPTraceExporter } = require("@opentelemetry/exporter-trace-otlp-http");
 73→  const { OTLPMetricExporter } = require("@opentelemetry/exporter-metrics-otlp-http");
 74→  const { OTLPLogExporter } = require("@opentelemetry/exporter-logs-otlp-http");
 75→
 76→  const tracerProvider = new BasicTracerProvider({
 77→    resource,
 78→    spanProcessors: [new BatchSpanProcessor(new OTLPTraceExporter({ url: `${endpoint}/v1/traces` }))],
 79→  });
 80→
 81→  const meterProvider = new MeterProvider({
 82→    resource,
 83→    readers: [
 84→      new PeriodicExportingMetricReader({
 85→        exporter: new OTLPMetricExporter({ url: `${endpoint}/v1/metrics` }),
 86→      }),
 87→    ],
 88→  });
 89→
 90→  const loggerProvider = new LoggerProvider({
 91→    resource,
 92→    processors: [new SimpleLogRecordProcessor(new OTLPLogExporter({ url: `${endpoint}/v1/logs` }))],
 93→  });
 94→
 95→  return { tracerProvider, meterProvider, loggerProvider };
 96→}
 97→
 98→function buildShutdown(
 99→  tracerProvider: BasicTracerProvider,
100→  meterProvider: MeterProvider,
101→  loggerProvider: LoggerProvider,
102→): () => Promise<void> {
103→  let alreadyShutDown = false;
104→
105→  return async () => {
106→    if (alreadyShutDown) return;
107→    alreadyShutDown = true;
108→
109→    await Promise.allSettled([
110→      tracerProvider.forceFlush().then(() => tracerProvider.shutdown()),
111→      meterProvider.forceFlush().then(() => meterProvider.shutdown()),
112→      loggerProvider.forceFlush().then(() => loggerProvider.shutdown()),
113→    ]);
114→  };
115→}
116→
117→function registerProviders(
118→  tracerProvider: BasicTracerProvider,
119→  meterProvider: MeterProvider,
120→  loggerProvider: LoggerProvider,
121→): void {
122→  const contextManager = new AsyncLocalStorageContextManager();
123→  contextManager.enable();
124→  context.setGlobalContextManager(contextManager);
125→
126→  trace.setGlobalTracerProvider(tracerProvider);
127→  metrics.setGlobalMeterProvider(meterProvider);
128→  logs.setGlobalLoggerProvider(loggerProvider);
129→}
130→
131→export function createNoopTelemetryHandle(): TelemetryHandle {
132→  return {
133→    tracerProvider: trace.getTracerProvider(),
134→    meterProvider: metrics.getMeterProvider(),
135→    loggerProvider: logs.getLoggerProvider(),
136→    exporterType: "noop",
137→    shutdown: async () => {},
138→  };
139→}
140→
141→/**
142→ * Initialize OpenTelemetry SDK.
143→ *
144→ * Reads OTEL_EXPORTER_OTLP_ENDPOINT from env to select exporter type.
145→ * Returns a TelemetryHandle with providers and a shutdown function.
146→ * Falls back to no-op handle on failure so the server can still start.
147→ */
148→export function initTelemetry(): TelemetryHandle {
149→  try {
150→    const resource = buildResource();
151→    const endpoint = process.env.OTEL_EXPORTER_OTLP_ENDPOINT;
152→
153→    const { tracerProvider, meterProvider, loggerProvider } = endpoint
154→      ? createOtlpProviders(resource, endpoint)
155→      : createConsoleProviders(resource);
156→
157→    registerProviders(tracerProvider, meterProvider, loggerProvider);
158→
159→    return {
160→      tracerProvider,
161→      meterProvider,
162→      loggerProvider,
163→      exporterType: endpoint ? "otlp" : "console",
164→      shutdown: buildShutdown(tracerProvider, meterProvider, loggerProvider),
165→    };
166→  } catch (error) {
167→    console.error("[telemetry] Failed to initialize OpenTelemetry SDK, falling back to no-op:", error);
168→    return createNoopTelemetryHandle();
169→  }
170→}
