/**
 * HTTP request tracing wrapper — wide event instrumentation.
 *
 * Implements the wide event pattern: one comprehensive OTel span per
 * request with all business context attached. Handlers enrich the span
 * via getRequestContext().set() throughout the request lifecycle.
 *
 * At request completion, all accumulated attributes are flushed onto
 * the span — workspace, user, conversation, entity counts, model info,
 * timing breakdowns, and anything else handlers chose to record.
 *
 * This replaces scattered log.info("started")/log.info("completed")
 * pairs with a single rich event that powers both debugging and dashboards.
 */

import { randomUUID } from "node:crypto";
import { trace, context, SpanStatusCode } from "@opentelemetry/api";
import { HttpError } from "./errors";
import { jsonError, withRequestIdHeader } from "./response";
import { httpDurationHistogram, httpRequestsCounter } from "../telemetry/metrics";
import { createRequestContext, type RequestAttributes } from "./request-context";

export type RouteRequest = Request & {
  params: Record<string, string>;
};

export type RouteHandler = (request: RouteRequest) => Response | Promise<Response>;

const tracer = trace.getTracer("brain-server");

function extractRequestId(request: Request): string {
  const headerValue = request.headers.get("x-request-id")?.trim();
  return headerValue && headerValue.length > 0 ? headerValue : randomUUID();
}

function flushAttributes(
  span: ReturnType<ReturnType<typeof tracer.startActiveSpan>["prototype"]>,
  attrs: Readonly<RequestAttributes>,
): void {
  for (const [key, value] of Object.entries(attrs)) {
    if (Array.isArray(value)) {
      span.setAttribute(key, value);
    } else {
      span.setAttribute(key, value);
    }
  }
}

export function withTracing(route: string, method: string, handler: RouteHandler): RouteHandler {
  return async (request: RouteRequest) => {
    const startedAt = performance.now();
    const requestId = extractRequestId(request);
    const url = new URL(request.url);

    // Extract path params that carry business context
    const workspaceId = request.params?.workspaceId;
    const conversationId = request.params?.conversationId;

    return tracer.startActiveSpan("brain.http.request", (span) => {
      // Create the wide-event context bag and bind it to OTel context
      const { ctx: reqCtx, otelContext } = createRequestContext();

      // Seed with HTTP attributes — always present
      span.setAttribute("http.method", method);
      span.setAttribute("http.route", route);
      span.setAttribute("http.target", url.pathname);
      span.setAttribute("request.id", requestId);

      // Seed business context from URL params (available before handler runs)
      if (workspaceId) {
        reqCtx.set({ "workspace.id": workspaceId });
      }
      if (conversationId) {
        reqCtx.set({ "conversation.id": conversationId });
      }

      // Extract user-agent for client identification
      const userAgent = request.headers.get("user-agent");
      if (userAgent) {
        reqCtx.set({ "http.user_agent": userAgent });
      }

      // Content length for payload size awareness
      const contentLength = request.headers.get("content-length");
      if (contentLength) {
        reqCtx.set({ "http.request.content_length": Number(contentLength) });
      }

      return context.with(otelContext, async () => {
        try {
          const response = await handler(request);
          const responseWithRequestId = withRequestIdHeader(response, requestId);
          const statusCode = responseWithRequestId.status;
          const durationMs = Number((performance.now() - startedAt).toFixed(2));

          // Flush all accumulated business context onto the span
          flushAttributes(span, reqCtx.getAttributes());

          // Final HTTP outcome attributes
          span.setAttribute("http.status_code", statusCode);
          span.setAttribute("duration_ms", durationMs);
          span.setStatus({ code: statusCode >= 400 ? SpanStatusCode.ERROR : SpanStatusCode.OK });
          span.end();

          // Metrics derived from the same attributes
          httpDurationHistogram.record(durationMs, {
            "http.method": method,
            "http.route": route,
            "http.status_code": statusCode,
          });
          httpRequestsCounter.add(1, {
            "http.method": method,
            "http.route": route,
            "http.status_code": statusCode,
          });

          return responseWithRequestId;
        } catch (error) {
          const durationMs = Number((performance.now() - startedAt).toFixed(2));
          const statusCode = error instanceof HttpError ? error.status : 500;

          // Flush accumulated context even on errors — wide event includes failure context
          flushAttributes(span, reqCtx.getAttributes());

          span.setAttribute("http.status_code", statusCode);
          span.setAttribute("duration_ms", durationMs);
          span.setAttribute("error", true);
          span.setStatus({
            code: SpanStatusCode.ERROR,
            message: error instanceof Error ? error.message : "unknown error",
          });
          span.recordException(error instanceof Error ? error : new Error(String(error)));
          span.end();

          httpDurationHistogram.record(durationMs, {
            "http.method": method,
            "http.route": route,
            "http.status_code": statusCode,
          });
          httpRequestsCounter.add(1, {
            "http.method": method,
            "http.route": route,
            "http.status_code": statusCode,
          });

          if (error instanceof HttpError) {
            return withRequestIdHeader(jsonError(error.message, error.status), requestId);
          }

          return withRequestIdHeader(jsonError("internal server error", 500), requestId);
        }
      });
    });
  };
}

