252→      messageId: input.messageId,
253→      entities: persistedEntities,
254→      relationships: persistedRelationships,
255→    });
256→
257→    if (onboardingBefore !== onboardingAfter) {
258→      input.deps.sse.emitEvent(input.messageId, {
259→        type: "onboarding_state",
260→        messageId: input.messageId,
261→        onboardingState: onboardingAfter,
262→      });
263→    }
264→
265→    input.deps.sse.emitEvent(input.messageId, {
266→      type: "assistant_message",
267→      messageId: input.messageId,
268→      text: assistantText,
269→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
270→    });
271→
272→    input.deps.sse.emitEvent(input.messageId, {
273→      type: "done",
274→      messageId: input.messageId,
275→    });
276→
277→    log.info("chat.message.process.execution.completed", "Chat message processing execution completed", {
278→      conversationId: input.conversationId,
279→      messageId: input.messageId,
280→      workspaceId: input.workspaceRecord.id as string,
281→      entityCount: persistedEntities.length,
282→      relationshipCount: persistedRelationships.length,
283→      durationMs: elapsedMs(startedAt),
284→    });
285→  } catch (error) {
286→    log.error("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
287→      conversationId: input.conversationId,
288→      messageId: input.messageId,
289→      workspaceId: input.workspaceRecord.id as string,
290→      durationMs: elapsedMs(startedAt),
291→    });
292→    const errorText = userFacingError(error, "chat processing failed");
293→    input.deps.sse.emitEvent(input.messageId, {
294→      type: "error",
295→      messageId: input.messageId,
296→      error: errorText,
297→    });
298→  }
299→}
300→
301→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
302→  return [...new Set(suggestions.map((value) => value.trim()))]
303→    .filter((value) => value.length > 0 && value.length <= 140)
304→    .slice(0, limit);
305→}
