    const onboardingAfter = await transitionOnboardingState({
      surreal: deps.surreal,
      workspaceRecord,
      workspace,
      onboardingAction: body.onboardingAction,
      now,
    });

    // Load branch context
    const branchChain = await loadBranchChain(deps.surreal, conversationId);
