        }

        await deps.surreal.update(conversationRecord).merge({ updatedAt: now });

        // Post-response hooks
        await refreshConversationTouchedBy(deps.surreal, conversationRecord);
        await maybeUpgradeConversationTitle(deps.surreal, conversationRecord);

