          surreal: deps.surreal,
          embeddingModel: deps.embeddingModel,
          embeddingDimension: deps.config.embeddingDimension,
          assistantMessageRecord,
          assistantText,
          entities: [],
        }).catch(() => undefined));

        log.info("chat.route.completed", "Chat response completed", {
